import React, { useState } from 'react';
import { CatalogFormCodeReplaceBanner } from './CatalogFormCodeReplaceBanner';
import { CatalogRenameCodeModal } from './CatalogRenameCodeModal';
import { useCatalogCodeReplacePending } from '../../hooks/useCatalogCodeReplacePending';
import type { CatalogFormHistoryRecord } from './CatalogFormHistorySlot';

type CatalogFormCodeReplaceSlotProps = {
  testIdPrefix: string;
  catalogKind: string;
  editing: CatalogFormHistoryRecord | null | undefined;
  renameMode?: 'preview' | 'confirm';
  reloadKey?: number;
};

/** Banner trên form edit khi mã đang pending/replace — Step 2u companion. */
export function CatalogFormCodeReplaceSlot({
  testIdPrefix,
  catalogKind,
  editing,
  renameMode = 'preview',
  reloadKey = 0,
}: CatalogFormCodeReplaceSlotProps): React.ReactElement | null {
  const { getForCode } = useCatalogCodeReplacePending(catalogKind, reloadKey);
  const [draftOpen, setDraftOpen] = useState(false);
  if (!editing?.code) return null;
  const pending = getForCode(editing.code);
  if (!pending) return null;

  return (
    <>
      <CatalogFormCodeReplaceBanner
        testIdPrefix={testIdPrefix}
        pending={pending}
        onViewDetail={pending.status === 'Draft' ? () => setDraftOpen(true) : undefined}
      />
      {pending.status === 'Draft' && (
        <CatalogRenameCodeModal
          testIdPrefix={testIdPrefix}
          isOpen={draftOpen}
          onClose={() => setDraftOpen(false)}
          catalogKind={catalogKind}
          oldCode={pending.oldCode}
          renameMode={renameMode}
          draftJobId={pending.jobId}
          viewDraftOnly
          onCompleted={() => setDraftOpen(false)}
        />
      )}
    </>
  );
}
