import React, { useEffect, useState } from 'react';
import { Button, Checkbox, Input, Modal, Select, dispatchAppToast } from '@linm-soft/common-components';
import { catalogUiSchemaService } from '../../../services/master/catalogUiSchemaService';
import { useAppDispatch } from '../../../store/hooks';
import type { CatalogUiField, CatalogUiGridConfig, CatalogUiSchema } from '../../../types/catalogUiSchema';
import { resolveApiErrorMessage } from '../../../utils/resolveApiErrorMessage';
import styles from '../../../styles/erpPage.module.css';

export interface CatalogUiSchemaEditorModalProps {
  testIdPrefix: string;
  catalogKind: string;
  isOpen: boolean;
  onClose: () => void;
  onSaved: (schema: CatalogUiSchema) => void;
}

const HEIGHT_MODE_OPTIONS = [
  { value: 'auto', label: 'Auto' },
  { value: 'fixed', label: 'Fixed' },
];

function patchField(
  fields: CatalogUiField[],
  key: string,
  patch: Partial<Pick<CatalogUiField, 'list' | 'lookup' | 'proposal'>>,
): CatalogUiField[] {
  return fields.map(f => {
    if (f.key !== key) return f;
    return {
      ...f,
      ...(patch.list != null ? { list: patch.list } : {}),
      ...(patch.lookup != null ? { lookup: patch.lookup } : {}),
      ...(patch.proposal != null ? { proposal: patch.proposal } : {}),
    };
  });
}

export const CatalogUiSchemaEditorModal: React.FC<CatalogUiSchemaEditorModalProps> = ({
  testIdPrefix,
  catalogKind,
  isOpen,
  onClose,
  onSaved,
}) => {
  const dispatch = useAppDispatch();
  const [draft, setDraft] = useState<CatalogUiSchema | null>(null);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    if (!isOpen) return;
    let cancelled = false;
    setLoading(true);
    catalogUiSchemaService
      .get(catalogKind, true)
      .then(data => {
        if (!cancelled) setDraft(data);
      })
      .catch(err => {
        if (!cancelled) {
          dispatchAppToast(dispatch, {
            message: resolveApiErrorMessage(err, 'Lỗi tải cấu hình'),
            type: 'error',
          });
        }
      })
      .finally(() => {
        if (!cancelled) setLoading(false);
      });
    return () => { cancelled = true; };
  }, [isOpen, catalogKind]);

  const editableFields = draft?.fields.filter(f => f.configurable !== false) ?? [];
  const isAccountsConfig = draft?.catalogKind === 'accounts';

  const updateList = (key: string, visible: boolean, width?: string) => {
    setDraft(prev => {
      if (!prev) return prev;
      return {
        ...prev,
        fields: patchField(prev.fields, key, {
          list: {
            visible,
            order: prev.fields.find(f => f.key === key)?.list?.order ?? 0,
            width: width ?? prev.fields.find(f => f.key === key)?.list?.width ?? undefined,
            variant: prev.fields.find(f => f.key === key)?.list?.variant ?? undefined,
          },
        }),
      };
    });
  };

  const updateLookup = (key: string, visible: boolean, width?: string, variant?: string) => {
    setDraft(prev => {
      if (!prev) return prev;
      const cur = prev.fields.find(f => f.key === key);
      return {
        ...prev,
        fields: patchField(prev.fields, key, {
          lookup: {
            visible,
            order: cur?.lookup?.order ?? 0,
            width: width ?? cur?.lookup?.width ?? undefined,
            variant: variant ?? cur?.lookup?.variant ?? undefined,
          },
        }),
      };
    });
  };

  const updateProposal = (key: string, editable: boolean) => {
    setDraft(prev => {
      if (!prev) return prev;
      const cur = prev.fields.find(f => f.key === key);
      return {
        ...prev,
        fields: patchField(prev.fields, key, {
          proposal: {
            editable,
            order: cur?.proposal?.order ?? 0,
          },
        }),
      };
    });
  };

  const patchGridConfig = (
    gridKey: 'masterGrid' | 'detailGrid',
    patch: Partial<CatalogUiGridConfig>,
  ) => {
    setDraft(prev => {
      if (!prev) return prev;
      const current = prev.tableConfig?.[gridKey] ?? {};
      return {
        ...prev,
        tableConfig: {
          ...(prev.tableConfig ?? {}),
          [gridKey]: {
            stickyHeader: true,
            heightMode: 'auto',
            height: null,
            resizableColumns: true,
            ...current,
            ...patch,
          },
        },
      };
    });
  };

  const handleSave = async () => {
    if (!draft) return;
    setSaving(true);
    try {
      const saved = await catalogUiSchemaService.save(catalogKind, {
        schemaVersion: draft.schemaVersion,
        fields: draft.fields.filter(f => f.configurable !== false),
        lookup: draft.lookup,
        list: draft.list,
        hintText: draft.hintText ?? null,
        tableConfig: draft.tableConfig ?? null,
      });
      dispatchAppToast(dispatch, { message: 'Đã lưu cấu hình hiển thị danh mục', type: 'success' });
      onSaved(saved);
      onClose();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: resolveApiErrorMessage(err, 'Lưu cấu hình thất bại'),
        type: 'error',
      });
    } finally {
      setSaving(false);
    }
  };

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title="Cấu hình hiển thị danh mục"
      size="lg"
    >
      <div className={styles.modalBody} data-testid={`${testIdPrefix}-schema-editor`}>
        {loading && <p>Đang tải…</p>}
        {!loading && draft && (
          <>
            <p className={styles.sharedCatalogHint}>
              Chọn cột hiển thị trên danh sách, lookup (form/chứng từ) và trường cho phép đề xuất sửa đổi.
            </p>
            {isAccountsConfig ? (
              <div className={styles.formGrid} style={{ marginBottom: 12 }}>
                <div className={styles.field}>
                  <label className={styles.label}>Hint header</label>
                  <Input
                    value={draft.hintText ?? ''}
                    placeholder="Nhập mô tả/hint cho Danh mục tài khoản"
                    data-testid={`${testIdPrefix}-schema-hint-text`}
                    onChange={e => setDraft(prev => prev ? { ...prev, hintText: e.target.value } : prev)}
                  />
                </div>
                <div className={styles.masterCodeNameRow}>
                  <div className={styles.field}>
                    <label className={styles.label}>Master grid — Height mode</label>
                    <Select
                      value={draft.tableConfig?.masterGrid?.heightMode ?? 'auto'}
                      options={HEIGHT_MODE_OPTIONS}
                      onChange={e => patchGridConfig('masterGrid', { heightMode: e.target.value as 'auto' | 'fixed' })}
                    />
                  </div>
                  <div className={styles.field}>
                    <label className={styles.label}>Master grid — Height</label>
                    <Input
                      value={draft.tableConfig?.masterGrid?.height ?? ''}
                      placeholder="vd: 420px"
                      onChange={e => patchGridConfig('masterGrid', { height: e.target.value || null })}
                    />
                  </div>
                </div>
                <div className={styles.masterCodeNameRow}>
                  <div className={styles.field}>
                    <Checkbox
                      label="Master grid sticky header"
                      checked={draft.tableConfig?.masterGrid?.stickyHeader ?? true}
                      onChange={e => patchGridConfig('masterGrid', { stickyHeader: e.target.checked })}
                    />
                  </div>
                  <div className={styles.field}>
                    <Checkbox
                      label="Master grid resizable columns"
                      checked={draft.tableConfig?.masterGrid?.resizableColumns ?? true}
                      onChange={e => patchGridConfig('masterGrid', { resizableColumns: e.target.checked })}
                    />
                  </div>
                </div>
                <div className={styles.masterCodeNameRow}>
                  <div className={styles.field}>
                    <label className={styles.label}>Detail grid — Height mode</label>
                    <Select
                      value={draft.tableConfig?.detailGrid?.heightMode ?? 'auto'}
                      options={HEIGHT_MODE_OPTIONS}
                      onChange={e => patchGridConfig('detailGrid', { heightMode: e.target.value as 'auto' | 'fixed' })}
                    />
                  </div>
                  <div className={styles.field}>
                    <label className={styles.label}>Detail grid — Height</label>
                    <Input
                      value={draft.tableConfig?.detailGrid?.height ?? ''}
                      placeholder="vd: 320px"
                      onChange={e => patchGridConfig('detailGrid', { height: e.target.value || null })}
                    />
                  </div>
                </div>
                <div className={styles.masterCodeNameRow}>
                  <div className={styles.field}>
                    <Checkbox
                      label="Detail grid sticky header"
                      checked={draft.tableConfig?.detailGrid?.stickyHeader ?? true}
                      onChange={e => patchGridConfig('detailGrid', { stickyHeader: e.target.checked })}
                    />
                  </div>
                  <div className={styles.field}>
                    <Checkbox
                      label="Detail grid resizable columns"
                      checked={draft.tableConfig?.detailGrid?.resizableColumns ?? true}
                      onChange={e => patchGridConfig('detailGrid', { resizableColumns: e.target.checked })}
                    />
                  </div>
                </div>
              </div>
            ) : null}
            <div className={styles.schemaEditorTableWrap}>
              <table className={styles.table}>
                <thead>
                  <tr>
                    <th>Trường</th>
                    <th>List</th>
                    <th>Rộng list</th>
                    <th>Lookup</th>
                    <th>Rộng lookup</th>
                    <th>Đề xuất</th>
                  </tr>
                </thead>
                <tbody>
                  {editableFields.map(f => (
                    <tr key={f.key}>
                      <td>
                        <strong>{f.label}</strong>
                        <br />
                        <code className={styles.schemaFieldKey}>{f.key}</code>
                      </td>
                      <td>
                        <Checkbox
                          id={`${testIdPrefix}-schema-list-cb-${f.key}`}
                          aria-label={`Hiển thị ${f.label} trên danh sách`}
                          checked={!!f.list?.visible}
                          data-testid={`${testIdPrefix}-schema-list-${f.key}`}
                          onChange={e => updateList(f.key, e.target.checked)}
                        />
                      </td>
                      <td>
                        <Input
                          value={f.list?.width ?? ''}
                          placeholder="8rem / 1fr"
                          disabled={!f.list?.visible}
                          data-testid={`${testIdPrefix}-schema-list-w-${f.key}`}
                          onChange={e => updateList(f.key, !!f.list?.visible, e.target.value)}
                        />
                      </td>
                      <td>
                        <Checkbox
                          id={`${testIdPrefix}-schema-lookup-cb-${f.key}`}
                          aria-label={`Hiển thị ${f.label} trên lookup`}
                          checked={!!f.lookup?.visible}
                          data-testid={`${testIdPrefix}-schema-lookup-${f.key}`}
                          onChange={e => updateLookup(f.key, e.target.checked)}
                        />
                      </td>
                      <td>
                        <Input
                          value={f.lookup?.width ?? ''}
                          placeholder="5rem"
                          disabled={!f.lookup?.visible}
                          data-testid={`${testIdPrefix}-schema-lookup-w-${f.key}`}
                          onChange={e => updateLookup(f.key, !!f.lookup?.visible, e.target.value)}
                        />
                      </td>
                      <td>
                        <Checkbox
                          id={`${testIdPrefix}-schema-proposal-cb-${f.key}`}
                          aria-label={`Cho phép đề xuất sửa ${f.label}`}
                          checked={!!f.proposal?.editable}
                          data-testid={`${testIdPrefix}-schema-proposal-${f.key}`}
                          onChange={e => updateProposal(f.key, e.target.checked)}
                        />
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
            <div className={styles.modalActions}>
              <Button variant="secondary" onClick={onClose}>Hủy</Button>
              <Button
                variant="primary"
                disabled={saving}
                data-testid={`${testIdPrefix}-schema-save`}
                onClick={() => void handleSave()}
              >
                {saving ? 'Đang lưu…' : 'Lưu cấu hình'}
              </Button>
            </div>
          </>
        )}
      </div>
    </Modal>
  );
};
